"""SessionStore — JSON file-based ACP session persistence with atomic write."""
from __future__ import annotations

import json
import logging
import time
from dataclasses import asdict, dataclass, field, fields
from datetime import datetime, timezone
from pathlib import Path

log = logging.getLogger(__name__)


@dataclass
class SessionRecord:
    """Represents a persisted ACP session."""

    session_id: str
    instance: str
    name: str | None = None
    first_prompt: str = ""
    agent_name: str = "kiro-cli"
    cwd: str = ""
    created_at: str = ""
    last_active_at: str = ""
    prompt_count: int = 0
    status: str = "active"  # active | archived | crashed
    short_hash: str = ""

    def __post_init__(self) -> None:
        if not self.short_hash and self.session_id:
            # Strip common prefixes and take first 6 alphanumeric chars
            raw = self.session_id.removeprefix("sess_")
            self.short_hash = raw[:6]
        if not self.created_at:
            self.created_at = datetime.now(timezone.utc).isoformat()
        if not self.last_active_at:
            self.last_active_at = self.created_at

    @property
    def display_name(self) -> str:
        """人類友善的 session 名稱（用於按鈕標籤）。"""
        if self.name:
            return self.name[:20] + "…" if len(self.name) > 20 else self.name
        if self.first_prompt:
            text = self.first_prompt[:20]
            return text + "…" if len(self.first_prompt) > 20 else text
        return f"Session {self.short_hash}"


class SessionStore:
    """JSON file-based session persistence with atomic write.

    存放位置：state/sessions.json
    所有 write 操作使用 tmp + rename 確保原子性。
    """

    def __init__(self, path: Path) -> None:
        self._path = path
        self._data: dict[str, SessionRecord] = {}
        self._load()

    def save(self, record: SessionRecord) -> None:
        """Save or update a session record."""
        record.last_active_at = datetime.now(timezone.utc).isoformat()
        self._data[record.session_id] = record
        self._flush()

    def get(self, session_id: str) -> SessionRecord | None:
        """Get a session by ID."""
        return self._data.get(session_id)

    def get_by_short_hash(self, instance: str, short_hash: str) -> SessionRecord | None:
        """Find a session by short hash within a specific instance."""
        for record in self._data.values():
            if record.instance == instance and record.short_hash == short_hash:
                return record
        return None

    def list_by_instance(self, instance: str, status: str | None = None) -> list[SessionRecord]:
        """List sessions for a specific instance, optionally filtered by status."""
        results = [
            r for r in self._data.values()
            if r.instance == instance and (status is None or r.status == status)
        ]
        # Sort by last_active_at descending (most recent first)
        results.sort(key=lambda r: r.last_active_at, reverse=True)
        return results

    def get_active_session(self, instance: str) -> SessionRecord | None:
        """Get the most recently active session for an instance."""
        active = self.list_by_instance(instance, status="active")
        return active[0] if active else None

    def archive(self, session_id: str) -> None:
        """Archive a session (mark as archived)."""
        record = self._data.get(session_id)
        if record:
            record.status = "archived"
            record.last_active_at = datetime.now(timezone.utc).isoformat()
            self._flush()

    def unarchive(self, session_id: str) -> None:
        """Restore an archived session to active status."""
        record = self._data.get(session_id)
        if record:
            record.status = "active"
            record.last_active_at = datetime.now(timezone.utc).isoformat()
            self._flush()

    def update_name(self, session_id: str, name: str) -> None:
        """Update session name (from agent auto-naming)."""
        record = self._data.get(session_id)
        if record:
            record.name = name
            self._flush()

    def set_first_prompt(self, session_id: str, prompt: str) -> None:
        """Record the first user prompt (used as fallback name)."""
        record = self._data.get(session_id)
        if record and not record.first_prompt:
            record.first_prompt = prompt[:100]
            self._flush()

    def increment_prompt_count(self, session_id: str) -> None:
        """Increment prompt count and update last_active_at."""
        record = self._data.get(session_id)
        if record:
            record.prompt_count += 1
            record.last_active_at = datetime.now(timezone.utc).isoformat()
            self._flush()

    def mark_crashed(self, session_id: str) -> None:
        """Mark a session as crashed."""
        record = self._data.get(session_id)
        if record:
            record.status = "crashed"
            self._flush()

    def delete(self, session_id: str) -> None:
        """Permanently delete a session record."""
        if session_id in self._data:
            del self._data[session_id]
            self._flush()

    # ─── Internal ────────────────────────────────────────────────

    def _load(self) -> None:
        """Load session data from disk."""
        if not self._path.exists():
            self._data = {}
            return
        try:
            raw = json.loads(self._path.read_text(encoding="utf-8"))
        except (json.JSONDecodeError, OSError) as e:
            log.warning("Failed to load session store: %s", e)
            self._data = {}
            return
        # 逐筆容錯（M6）：一筆帶未知欄位（版本升級後 downgrade、手動編輯）
        # 不能整包清空——否則下一次 _flush 會把 sessions.json 覆寫成空
        known = {f.name for f in fields(SessionRecord)}
        self._data = {}
        for sid, record_data in raw.items():
            try:
                filtered = {k: v for k, v in dict(record_data).items() if k in known}
                self._data[sid] = SessionRecord(**filtered)
            except (TypeError, ValueError) as e:
                log.warning("Skipping bad session record %s: %s", sid, e)

    def _flush(self) -> None:
        """Atomic write: write to tmp file then rename."""
        self._path.parent.mkdir(parents=True, exist_ok=True)
        data = {sid: asdict(r) for sid, r in self._data.items()}
        tmp_path = self._path.with_suffix(".tmp")
        tmp_path.write_text(
            json.dumps(data, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
        tmp_path.replace(self._path)  # Atomic on same filesystem

import { readFile, writeFile, unlink } from "node:fs/promises";
import path from "node:path";
import { config } from "./config.js";
import { loadFacts, buildPreambleWithBreakdown, buildLocalPreamble } from "./memory.js";
import { formatActiveRelayTasksForPreamble } from "./working-state.js";
import { petState } from "./pet-server.js";
import { AcpProvider, DirectProvider, resolveBaseUrl, type Provider, type ProviderType, type SessionUpdate } from "./provider/index.js";
import { logEvent } from "./event-log.js";
import { recordSeqObservation, appendToolName, TURN_MARKER } from "./tool-observer.js";
import { exportSession, saveArchive, type SessionArchive } from "./session-archive.js";
import { loadAcpProviders, type AcpBackendDef } from "./acp-providers.js";

const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;

// ─── Pinned agent persistence ─────────────────────────────────────────────────
const PINNED_AGENT_PATH = path.join(config.memoryDir, "config", "pinned-agent.json");

async function loadPinnedAgents(): Promise<Map<number, string>> {
  try {
    const raw = await readFile(PINNED_AGENT_PATH, "utf8");
    const obj: Record<string, string> = JSON.parse(raw);
    const map = new Map<number, string>();
    for (const [k, v] of Object.entries(obj)) {
      const chatId = Number(k);
      if (!isNaN(chatId) && v) map.set(chatId, v);
    }
    return map;
  } catch {
    return new Map();
  }
}

async function savePinnedAgents(map: Map<number, string>): Promise<void> {
  const obj: Record<string, string> = {};
  for (const [k, v] of map) obj[String(k)] = v;
  await writeFile(PINNED_AGENT_PATH, JSON.stringify(obj, null, 2), "utf8");
}
// ──────────────────────────────────────────────────────────────────────────────

function maskCodeRegionsForRelayCapture(text: string): { masked: string; restore: (s: string) => string } {
  const slots: string[] = [];
  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
    const idx = slots.length;
    slots.push(m);
    return `\u0000CODE${idx}\u0000`;
  });
  const restore = (s: string) =>
    s.replace(CODE_PLACEHOLDER_RE, (_m, i: string) => slots[Number(i)] ?? "");
  return { masked, restore };
}

export function isRelayDelegatePlaceholderGoal(goal: string): boolean {
  const g = goal.trim();
  return g === "" || g === "..." || g === "…" || /^<[^>\r\n]*>?$/.test(g);
}

export function captureRelayDelegateTokensFromText(buffer: string, existing: string[] = []): string[] {
  const next = [...existing];
  const { masked, restore } = maskCodeRegionsForRelayCapture(buffer);
  let m: RegExpExecArray | null;
  RELAY_DELEGATE_RE.lastIndex = 0;
  while ((m = RELAY_DELEGATE_RE.exec(masked)) !== null) {
    const goal = m[2]?.trim() ?? "";
    if (isRelayDelegatePlaceholderGoal(goal)) continue;
    const token = restore(m[0]);
    if (!next.includes(token)) next.push(token);
  }
  return next;
}

export interface HistoryEntry {
  role: "user" | "assistant";
  text: string;
  timestamp: number;
}

/**
 * Per-Telegram-chat session. Each chat owns its own Kiro ACP subprocess,
 * so conversations stay isolated.
 */
export interface ChatSession {
  chatId: number;
  userId?: number;
  client: Provider;
  /** Which provider type is active for this session. */
  activeProvider: ProviderType;
  /**
   * Which ACP backend (acp-providers.json key) this session's subprocess was
   * spawned from. undefined = the .env agent (no /agent switch yet) or a
   * non-ACP provider.
   */
  acpBackend?: string;
  sessionId: string;
  lastUsed: number;
  /** Accumulated assistant text for the in-flight turn. */
  buffer: string;
  /** Accumulated thinking text for the in-flight turn (local model only). */
  thinkingBuffer?: string;
  /** Human-readable tool/status lines for the in-flight turn. */
  toolLog: string[];
  /** Rolling buffer of the agent's latest stderr output. */
  stderrTail: string;
  /** Called whenever new streamed text is appended. */
  onUpdate?: (session: ChatSession) => void;
  /** Conversation history for /save export. */
  history: HistoryEntry[];
  /** Cumulative characters sent by user (approximate context-in). */
  charsIn: number;
  /** Cumulative characters emitted by agent (approximate context-out). */
  charsOut: number;
  /** Latest usage meta reported by agent (tokens, etc.), if any. */
  usage?: Record<string, unknown>;
  /** Long-term memory preamble to inject on first prompt. */
  memoryPreamble: string;
  /**
   * Char-length breakdown of `memoryPreamble`. Captured once at session
   * create so the /context and streaming-footer UI can show where the
   * preamble tokens are going (tool notes / env block / memory block)
   * without having to re-measure the string.

