  private inBuf: Buffer = Buffer.alloc(0);
  /** Outbound framing. Flipped to the peer's framing once we see one. */
  private outFraming: Framing = "line";
  /** Set once we've positively identified the peer's framing. */
  private framingLocked = false;
  private sessionId: string | null = null;
  private closed = false;
  /** Protocol-level JSON-RPC tracer; set once the session id is known. */
  private _tracer: AcpTracer | null = null;

  /** ACP protocol tracer (null until session/new completes). */
  get tracer(): AcpTracer | null {
    return this._tracer;
  }

  /** Subprocess PID for health monitoring. */
  get pid(): number | undefined {
    return this.proc?.pid;
  }

  /**
   * On Windows, batch files (.bat/.cmd) and PowerShell scripts (.ps1) can't
   * be launched directly by CreateProcess — they need a shell interpreter.
   * Bare commands without an extension (e.g. "kiro-cli", "npx") also need
   * the shell so PATHEXT can resolve them to the right .cmd/.exe shim.
   * On POSIX we never need shell (the kernel handles shebangs).
   */
  private static commandNeedsShell(command: string): boolean {
    if (process.platform !== "win32") return false;
    const trimmed = command.trim();
    if (/\.(?:bat|cmd|ps1)$/i.test(trimmed)) return true;
    // If the command has no extension, let cmd.exe resolve it via PATHEXT.
    // node.exe, foo.exe and absolute paths to .exe files don't need a shell.
    const base = trimmed.replace(/^.*[\\/]/, "");
    return !/\.[^.\\/]+$/.test(base);
  }

