   * Quote a token for cmd.exe. We only need to handle the common cases:
   * values with spaces, and values with embedded double quotes. cmd.exe's
   * quoting rules are primitive — wrap in double quotes and escape any
   * embedded quotes by doubling them.
   */
  private static quoteForShell(token: string): string {
    if (token === "") return '""';
    if (!/[\s"&|<>^()]/.test(token)) return token;
    return `"${token.replace(/"/g, '""')}"`;
  }

