    // about passing args alongside `shell: true` and also sidesteps any
    // shell-quoting surprises in the args array.
    const needsShell = AcpClient.commandNeedsShell(opts.command);
    if (needsShell) {
      // When shell is required, build a single quoted command string and
      // pass empty args — that's the API shape Node wants post-DEP0190.
      const cmdLine = [opts.command, ...opts.args]
        .map(AcpClient.quoteForShell)
        .join(" ");
      this.proc = spawn(cmdLine, [], {
        cwd: opts.cwd,
        env: buildSpawnEnv(opts.env),
        stdio: ["pipe", "pipe", "pipe"],
        shell: true,
      });
    } else {
      this.proc = spawn(opts.command, opts.args, {
        cwd: opts.cwd,
        env: buildSpawnEnv(opts.env),
        stdio: ["pipe", "pipe", "pipe"],
      });
    }

