      this.closed = true;
      for (const { reject } of this.pending.values()) {
        reject(new Error(`ACP agent exited with code ${code}`));
      }
      this.pending.clear();
      this.emit("exit", code);
    });
    this.proc.on("error", (err) => {
      this.emit("stderr", `spawn error: ${err.message}\n`);
    });
  }

