import { EventEmitter } from "node:events";
import { AcpClient, AcpClientOptions, SessionUpdate as AcpSessionUpdate } from "../acpClient.js";
import type { Provider, SessionUpdate } from "./types.js";

export interface AcpProviderOptions extends AcpClientOptions {
  /** Working directory passed to session/new. */
  sessionCwd: string;
  /** MCP servers to register with the ACP agent. */
  mcpServers?: unknown[];
}

/**
 * Provider implementation that delegates to the existing AcpClient
 * (Kiro CLI subprocess over JSON-RPC stdio). This is a thin adapter
 * so SessionManager can treat ACP and Direct providers uniformly.
 */
export class AcpProvider extends EventEmitter implements Provider {
  readonly name = "acp";
  private client: AcpClient;
  private initialized = false;
  private _sessionId = "";

  constructor(private opts: AcpProviderOptions) {
    super();
    this.client = new AcpClient(opts);

    // Forward events from AcpClient → Provider interface
    this.client.on("update", (u: AcpSessionUpdate) => {
      this.emit("update", u as SessionUpdate);
    });
    this.client.on("stderr", (chunk: string) => this.emit("stderr", chunk));
    this.client.on("exit", (code: number | null) => this.emit("exit", code));
    this.client.on("request", (req) => this.emit("request", req));
  }

  /** Must be called once before prompt(). Returns the ACP session ID. */
  async initialize(): Promise<string> {
    this._sessionId = await this.client.initializeAndCreateSession(
      this.opts.sessionCwd,
      this.opts.mcpServers,
    );
    this.initialized = true;
    return this._sessionId;
  }

  get sessionId(): string {
    return this._sessionId;
  }

  async prompt(text: string): Promise<{ stopReason: string }> {
    if (!this.initialized) throw new Error("AcpProvider not initialized");
    return this.client.prompt(text);
  }

  cancel(): void {
    this.client.cancel();
  }

  async close(): Promise<void> {
    await this.client.close();
  }

  get isClosed(): boolean {
    return this.client.isClosed;
  }

  /** Expose subprocess PID for health monitoring. */
  get pid(): number | undefined {
    return this.client.pid;
  }
}

  }

  if ("method" in msg && "id" in msg) {
    // Agent -> Client request (e.g. session/request_permission, fs/*).
    // We auto-reply with permissive defaults to keep things moving.
    this.emit("request", msg as JsonRpcRequest);
    this.handleAgentRequest(msg as JsonRpcRequest);
    return;
  }

  if ("method" in msg) {
    // Notification
    if (msg.method === "session/update") {
      this.emit("update", msg.params as SessionUpdate);
    }
    return;
  }
}

private handleAgentRequest(req: JsonRpcRequest) {
  // The user wants "fully open" access, so we grant any permission
  // request and return empty for anything else we don't implement.
  if (req.method === "session/request_permission") {
    const params = (req.params ?? {}) as {
      toolCall?: { kind?: string; title?: string };
      options?: { optionId: string; name?: string; kind?: string }[];
    };
    if (this.opts.permissionMode === "readonly") {
      const kind = params.toolCall?.kind ?? "";
      const MUTATING = new Set(["edit", "delete", "move", "execute"]);
      if (MUTATING.has(kind)) {
        const reject =
          params.options?.find((o) => o.kind === "reject_always") ??
          params.options?.find((o) => o.kind === "reject_once");
        console.warn(
          `[acp] readonly mode denied "${kind}" tool call (${params.toolCall?.title ?? "?"})`);
        this.sendResponse(req.id, reject
          ? { outcome: { outcome: "selected", optionId: reject.optionId } }
          : { outcome: { outcome: "cancelled" } });
        return;
      }
    }
    const allow =
      params.options?.find((o) => o.kind === "allow_always") ??
      params.options?.find((o) => o.kind === "allow_once") ??
      params.options?.[0];
    this.sendResponse(req.id, {
      outcome: {
        outcome: "selected",
        optionId: allow?.optionId ?? "allow",
      },
    });
    return;
  }
  // Fallback: respond with an empty object so the agent isn't stuck.
  this.sendResponse(req.id, {});
}

private writeMessage(obj: unknown) {
  if (this.closed) throw new Error("ACP agent has exited");
  this._tracer?.logSend(obj);
  const payload = JSON.stringify(obj);
  if (this.outFraming === "lsp") {
    const body = Buffer.from(payload, "utf8");
    const header = `Content-Length: ${body.length}\r\n\r\n`;
    this.proc.stdin.write(header);
    this.proc.stdin.write(body);
  } else {
    this.proc.stdin.write(payload + "\n");
  }
}

private sendResponse(id: JsonRpcId, result: unknown) {
  this.writeMessage({ jsonrpc: "2.0", id, result });
}

private call<T = unknown>(method: string, params?: unknown): Promise<T> {
  const id = this.nextId++;
  return new Promise<T>((resolve, reject) => {
    this.pending.set(id, {
      resolve: (v) => resolve(v as T),
      reject,
    });
    this.writeMessage({ jsonrpc: "2.0", id, method, params });
  });
}

async initializeAndCreateSession(cwd: string, mcpServers?: any[]): Promise<string> {
  await this.call("initialize", {
    protocolVersion: 1,
    clientCapabilities: {
      fs: { readTextFile: true, writeTextFile: true },
      terminal: true,
    },
    clientInfo: {
      name: "telegram-kiro-bridge",
      title: "Telegram ↔ Kiro Bridge",
      version: "0.1.0",
    },
  });

