private async create(chatId: number, userId?: number, providerType?: ProviderType): Promise<ChatSession> {
  // Inject TG_ACTIVE_USER_ID so MCP children (mcp-memory) know whose
  // facts file to write. MEMORY_DIR is passed through too so the mcp
  // server doesn't need to re-read .env.
  const env: Record<string, string> = { MEMORY_DIR: config.memoryDir };
  if (userId) env.TG_ACTIVE_USER_ID = String(userId);

  const activeType = providerType ?? config.defaultProvider;

  // Resolve the pinned ACP backend (/agent). Looked up on EVERY create —
  // including crash-recreates via get() — so the chosen backend sticks.
  let backend: AcpBackendDef | undefined;
  if (activeType === "acp") {
    const key = this.acpBackendByChat.get(chatId);
    if (key) {
      backend = loadAcpProviders()[key];
      if (!backend) {
        console.warn(
          `[session ${chatId}] pinned ACP backend "${key}" not in acp-providers.json — falling back to .env agent`,
        );
        this.acpBackendByChat.delete(chatId);
        savePinnedAgents(this.acpBackendByChat).catch(() => {});
      }
    }
  }

  const facts = userId ? await loadFacts(userId) : "";

  // Try to compress recent facts via local LLM (graceful fallback if unavailable)
  let compressed: string | null = null;
  if (facts && activeType !== "local") {
    const lines = facts.split(/\r?\n/).filter(l => l.trim().length > 0);
    const tail = config.memoryPreambleTail;
    if (lines.length > tail) {
      const { compressFactsForPreamble: compress } = await import("./local-llm.js");
      compressed = await compress(lines.slice(-tail));
    }
  }
  const breakdown = activeType === "local"
    ? buildLocalPreamble(facts, userId)
    : buildPreambleWithBreakdown(facts, userId, { compressed, agentCommand: backend?.command });

  // Inject working-state from previous session if available (one-shot).
  const wsPath = path.join(config.memoryDir, `working-state-${chatId}.md`);
  let workingStateBlock = "";
  try {
    const ws = await readFile(wsPath, "utf8");
    workingStateBlock =
      "\n[Previous session working state — use as context to resume work]\n" +
      ws +
      "\nResume from `next_action` above. Do not ask what was done last time.\n" +
      "[End working state]\n\n";
    await unlink(wsPath);
    console.log(`[session] injected working-state for chat ${chatId}`);
  } catch { /* file doesn't exist — normal */ }

  // Inject structured session archive restoration (complements working-state
  // with turn-level context, goal state, and session stats).
  let archiveBlock = "";
  let priorArchive: SessionArchive | undefined;
  try {
    const { loadArchive, buildRestorationBlock, deleteArchive } = await import("./session-archive.js");
    const archive = await loadArchive(chatId);
    if (archive) {
      archiveBlock = "\n" + buildRestorationBlock(archive) + "\n\n";
      await deleteArchive(chatId);
      priorArchive = archive; // stash for trivial-session carry-forward on close
      console.log(`[session] injected session archive for chat ${chatId} (${archive.stats.turnCount} turns, closed=${archive.closeReason})`);
    }
  } catch (err) {
    console.error(`[session] loadArchive failed for chat ${chatId}:`, (err as Error).message);
  }

  // Inject pending dream suggestions (High Priority from last /dream run).
  // Read-only：STATE.md 由 dream 每晚重寫，這裡不刪。48h 新鮮度閘門防止
  // 注入陳年建議。Frozen-snapshot 合規：只在 create() 組一次，隨 preamble 凍結。
  let dreamStateBlock = "";
  try {
    const { readLoopStateHighPriority, loopStatePath } = await import("./loop-state.js");
    const hp = readLoopStateHighPriority();
    const fresh = hp?.lastRun && Date.now() - hp.lastRun.getTime() < 48 * 3600_000;
    if (hp && fresh && hp.items.length > 0) {
      dreamStateBlock =
        "\n[Pending dream suggestions — 上次 /dream 維運的 High Priority 待辦]\n" +
        hp.items.map((it) => `- ${it}`).join("\n") +
        "\n當使用者說「處理建議」「dream 建議」或類似語句時，即指上述項目。\n" +
        `完整三層清單（含 Watch List）在 ${loopStatePath()}。處理完某項後，更新該檔移除或標記已處理。\n` +
        "[End pending dream suggestions]\n\n";
      console.log(`[session] injected ${hp.items.length} pending dream suggestion(s) for chat ${chatId}`);
    }
  } catch { /* fail-open：STATE.md 缺失或格式不符不影響 session 建立 */ }

  const relayTaskBlock = await formatActiveRelayTasksForPreamble(chatId);
  const preambleText = breakdown.text + workingStateBlock + archiveBlock + dreamStateBlock + relayTaskBlock;
  const provider = this.createProvider(activeType, env, preambleText, backend);
  const session: ChatSession = {
    chatId,
    userId,
    client: provider,
    activeProvider: activeType,
    acpBackend: backend?.key,
    sessionId: "",
    lastUsed: Date.now(),
    buffer: "",
    toolLog: [],
    stderrTail: "",
    history: [],
    charsIn: 0,
    charsOut: 0,
    memoryPreamble: preambleText,
    preambleBreakdown: {
      total: preambleText.length,
      toolNotes: breakdown.toolNotes,
      envBlock: breakdown.envBlock,
      memoryBlock: breakdown.memoryBlock,
      dailylogBlock: breakdown.dailylogBlock,
    },
    preambleInjected: activeType !== "acp" ? true : false, // Direct providers use system message; ACP needs user-message injection
    tailFacts: breakdown.tailFacts,
    injectedWikiSlugs: new Set(),
    injectedSkills: new Set(),
    inflight: false,
    _pendingMetaQueue: [],
    _consecutiveToolFails: 0,
    priorArchive,
  };

  provider.on("update", (u: SessionUpdate) => this.applyUpdate(session, u));
  provider.on("stderr", (chunk) => {
    // Keep the tail so we can surface it with error messages.
    session.stderrTail = (session.stderrTail + chunk).slice(-2000);
    // Surface only when debugging; keep quiet otherwise.
    if (process.env.DEBUG_ACP) {
      console.error(`[acp ${chatId}] ${chunk.trimEnd()}`);
    }
  });
  provider.on("exit", (code) => {
    console.error(`[acp ${chatId}] agent exited (code=${code})`);
    // Only fire the unexpected-exit hook if this session is still registered.
    // Planned shutdowns (drop/sweepIdle/shutdown) remove it from the map first.
    const stillRegistered = this.sessions.get(chatId) === session;
    if (stillRegistered) {
      this.sessions.delete(chatId);
      if (this.onUnexpectedExit) {
        this.onUnexpectedExit(session, code).catch((e) =>
          console.error(`[session ${chatId}] onUnexpectedExit failed:`, e),
        );
      }
    }
  });

  session.sessionId = await provider.initialize();
  this.sessions.set(chatId, session);
  logEvent("session_start", { provider: activeType, backend: backend?.key, sessionId: session.sessionId }, { chatId, userId });
  return session;
}

/** Factory: create the right Provider based on type. */
private createProvider(type: ProviderType, env: Record<string, string>, systemPrompt?: string, backend?: AcpBackendDef): Provider {
  if (type === "acp") {
    // With a pinned backend (/agent), its table entry replaces the .env
    // agent wholesale — including the model/effort pin (undefined = leave
    // the adapter's own default untouched, NOT fall back to .env's pin).
    return new AcpProvider({
      command: backend?.command ?? config.agent.command,
      args: backend?.args ?? config.agent.args,
      cwd: config.sessionCwd,
      env,
      promptRetries: config.acpPromptRetries,
      promptRetryBaseMs: config.acpPromptRetryBaseMs,
      acpModel: backend ? (backend.model ?? "") : config.acpModel,
      acpEffort: backend ? (backend.effort ?? "") : config.acpEffort,
      sessionCwd: config.sessionCwd,
    });
  }
  // All other types use DirectProvider
  const modelKey = type as keyof typeof config.models;
  const apiKeyKey = type as keyof typeof config.apiKeys;
  return new DirectProvider({
    type,
    model: config.models[modelKey] ?? config.models.local,
    baseUrl: resolveBaseUrl(type, config.ollamaUrl),
    apiKey: config.apiKeys[apiKeyKey] ?? "",
    systemPrompt,
    mcpEnv: env,
    // Local models have limited context — keep the server set focused.
    mcpServerFilter: type === "local" ? ["memory", "notebooklm", "google"] : undefined,
  });
}

/**
 * Switch the active provider for a chat. Closes the old session and
 * creates a new one with the specified provider type.
 * Returns the new session.
 */
async switchProvider(chatId: number, type: ProviderType, userId?: number): Promise<ChatSession> {
  const existing = this.sessions.get(chatId);
  if (existing) {
    this.sessions.delete(chatId);
    await existing.client.close().catch(() => {});
  }
  return this.create(chatId, userId, type);
}

/**
 * Switch the ACP backend for a chat (/agent) with conversation handoff.
 * Reuses the full drop() close pipeline — archiveOnClose (substantive
 * guard + priorArchive carry-forward + LLM summary), onBeforeClose
 * (transcript + working-state) — so the new session's create() finds the
 * archive on disk and injects the handoff context into its preamble.
 * Throws when the backend key is unknown or a turn is in flight.
 */
async switchAgent(chatId: number, backendKey: string, userId?: number): Promise<ChatSession> {
  const def = loadAcpProviders()[backendKey];
  if (!def) {
    throw new Error(`未知的 agent "${backendKey}"（不在 acp-providers.json）`);
  }
  const existing = this.sessions.get(chatId);
  if (existing?.inflight) {
    throw new Error("目前有 turn 進行中，請等它完成或先 /cancel 再切換");
  }
  if (existing) {
    await this.drop(chatId, "agent_switch");
  }
  this.acpBackendByChat.set(chatId, backendKey);
  savePinnedAgents(this.acpBackendByChat).catch((err) =>
    console.warn(`[session ${chatId}] failed to persist pinned agent:`, err),
  );
  return this.create(chatId, userId, "acp");
}

/** Start (or restart) the inactivity timer for a turn. */
startInactivityTimer(session: ChatSession) {
  this.clearInactivityTimer(session);
  const ms = session._toolInFlight && config.turnToolInactivityTimeoutMs > 0
    ? config.turnToolInactivityTimeoutMs
    : config.turnInactivityTimeoutMs;
  if (ms <= 0) return;
  session._inactivityTimer = setTimeout(() => {
    console.warn(
      `[session ${session.chatId}] turn inactivity timeout (${ms}ms, toolInFlight=${!!session._toolInFlight}) — auto-cancelling`,
    );
    session.client.cancel();
  }, ms);
  session._inactivityTimer.unref?.();
}

private resetInactivityTimer(session: ChatSession) {
  if (!session._inactivityTimer) return;
  this.startInactivityTimer(session);
}

