//
// If the agent needs env vars (OPENAI_API_KEY, GEMINI_API_KEY, …), set
// them in your shell before running this script — they inherit.

import { AcpClient } from "../dist/acpClient.js";

function parseArgs(argv) {
  // Pull --timeout <ms> out of anywhere in argv; remainder is command+args.
  let timeoutMs = 20_000;
  const rest = [];
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--timeout" || a === "-t") {
      const next = argv[i + 1];
      const n = Number(next);
      if (!Number.isFinite(n) || n <= 0) {
        console.error(`error: --timeout expects a positive number, got: ${next}`);
        process.exit(2);
      }
      timeoutMs = n;
      i++;
    } else {
      rest.push(a);
    }
  }
  if (rest.length === 0) {
    console.error(
      "usage: node scripts/check-acp-handshake.mjs <command> [args...] [--timeout <ms>]",
    );
    console.error("");
    console.error("examples:");
    console.error("  node scripts/check-acp-handshake.mjs kiro-cli acp");
    console.error("  node scripts/check-acp-handshake.mjs codex-acp");
    console.error("  node scripts/check-acp-handshake.mjs gemini --experimental-acp");
    process.exit(2);
  }
  return { command: rest[0], args: rest.slice(1), timeoutMs };
}

function withTimeout(promise, ms, label) {
  let timer;
  const timeout = new Promise((_, reject) => {
    timer = setTimeout(() => {
      reject(new Error(`${label} timed out after ${ms}ms`));
    }, ms);
  });
  return Promise.race([
