/**
 * Windows-friendly rename: on NTFS, `rename()` can transiently fail with
 * EPERM/EBUSY when the target file is briefly held open by another
 * reader (antivirus, indexer, or even our own just-closed readFile on a
 * slow GC). POSIX fs do not exhibit this. Retry with exponential backoff
 * up to ~500ms, matching what git / electron-builder / pnpm do on
 * Windows.
 *
 * Non-Windows: single attempt, no retry needed.
 */
async function renameWithWindowsRetry(
  tmpPath: string,
  targetPath: string,
): Promise<void> {
  if (process.platform !== "win32") {
    await rename(tmpPath, targetPath);
    return;
  }
  const delays = [0, 10, 25, 50, 100, 150, 200]; // sum ≈ 535ms
  let lastErr: unknown;
  for (const d of delays) {
    if (d > 0) await new Promise((r) => setTimeout(r, d));
    try {
      await rename(tmpPath, targetPath);
      return;
    } catch (err: any) {
      if (err?.code !== "EPERM" && err?.code !== "EBUSY") throw err;
      lastErr = err;
    }
  }
  throw lastErr;
}

