```ts
  async initializeAndCreateSession(cwd: string, mcpServers?: any[]): Promise<string> {
    const { sessionId } = await this.initializeOrLoadSession(cwd, mcpServers);
    return sessionId;
  }

  /**
   * initialize 後建立或恢復 session。
   * resumeSessionId 有值且 agent 宣告 loadSession capability 時先試
   * session/load（成功 → resumed:true，跳過 applyModelEffort——session
   * 內已有 model 狀態）；capability 缺失或 load 失敗一律 fallback 到
   * session/new（同一 subprocess，不重 spawn）。
   */
  async initializeOrLoadSession(
    cwd: string,
    mcpServers?: any[],
    resumeSessionId?: string,
  ): Promise<{ sessionId: string; resumed: boolean }> {
    const initRes = await this.call<{ agentCapabilities?: { loadSession?: boolean } }>("initialize", {
      protocolVersion: 1,
      clientCapabilities: {
        fs: { readTextFile: true, writeTextFile: true },
        terminal: true,
      },
      clientInfo: {
        name: "telegram-kiro-bridge",
        title: "Telegram ↔ Kiro Bridge",
        version: "0.1.0",
      },
    });
    this.agentCapabilities = initRes?.agentCapabilities ?? {};

    if (resumeSessionId && this.agentCapabilities.loadSession === true) {
      this.replaying = true;
      try {
        await this.call("session/load", {
          sessionId: resumeSessionId,
          cwd,
          mcpServers: mcpServers ?? [],
        });
        this.sessionId = resumeSessionId;
        this._tracer = new AcpTracer(resumeSessionId);
        return { sessionId: resumeSessionId, resumed: true };
      } catch (err) {
        this.emit("stderr", `[acp] session/load failed, falling back to session/new: ${(err as Error).message}\n`);
      } finally {
        this.replaying = false;
      }
    }

    const res = await this.call<{ sessionId: string }>("session/new", {
      cwd,
      mcpServers: mcpServers ?? [],
    });
    this.sessionId = res.sessionId;
    this._tracer = new AcpTracer(res.sessionId);
    await this.applyModelEffort();
    return { sessionId: res.sessionId, resumed: false };
  }
```

