  private _resumed = false;

  /** initialize() 是否以 session/load 成功恢復（fallback 到 new 時為 false）。 */
  get resumed(): boolean {
    return this._resumed;
  }

  /** Must be called once before prompt(). Returns the ACP session ID. */
  async initialize(): Promise<string> {
    const { sessionId, resumed } = await this.client.initializeOrLoadSession(
      this.opts.sessionCwd,
      this.opts.mcpServers as any[] | undefined,
      this.opts.resumeSessionId,
    );
    this._sessionId = sessionId;
    this._resumed = resumed;
    this.initialized = true;
    return this._sessionId;
  }
