// Fake ACP agent — line-delimited JSON-RPC over stdio，供 smoke test 用。
// 支援 initialize / session/new / session/load（帶 replay）/ session/prompt。
// env FAKE_ACP_NO_LOADCAP=1 時 initialize 不宣告 loadSession capability。
// env FAKE_ACP_LOAD_FAIL=1 時 session/load 回 JSON-RPC error。
import { createInterface } from "node:readline";

const send = (obj) => process.stdout.write(JSON.stringify(obj) + "\n");
const rl = createInterface({ input: process.stdin });

rl.on("line", (line) => {
  let msg;
  try { msg = JSON.parse(line); } catch { return; }
  if (!("method" in msg)) return; // ignore responses

  if (msg.method === "initialize") {
    send({ jsonrpc: "2.0", id: msg.id, result: {
      protocolVersion: 1,
      agentCapabilities: {
        loadSession: process.env.FAKE_ACP_NO_LOADCAP === "1" ? false : true,
      },
    }});
    return;
  }
  if (msg.method === "session/new") {
    send({ jsonrpc: "2.0", id: msg.id, result: { sessionId: "sess_fake_new" } });
    return;
  }
  if (msg.method === "session/load") {
    if (process.env.FAKE_ACP_LOAD_FAIL === "1") {
      send({ jsonrpc: "2.0", id: msg.id, error: { code: -32001, message: "session not found" } });
      return;
    }
    const sid = msg.params?.sessionId ?? "";
    // Replay 兩則歷史（含一個危險 token，驗證抑制）
    send({ jsonrpc: "2.0", method: "session/update", params: {
      sessionId: sid, update: { sessionUpdate: "user_message_chunk",
        content: { type: "text", text: "舊訊息" } } }});
    send({ jsonrpc: "2.0", method: "session/update", params: {
      sessionId: sid, update: { sessionUpdate: "agent_message_chunk",
        content: { type: "text", text: "舊回覆 <<ASK:old|a=別按>>" } } }});
    send({ jsonrpc: "2.0", id: msg.id, result: null });
    return;
  }
  if (msg.method === "session/prompt") {
    send({ jsonrpc: "2.0", method: "session/update", params: {
      sessionId: msg.params?.sessionId, update: { sessionUpdate: "agent_message_chunk",
        content: { type: "text", text: "新回覆" } } }});
    send({ jsonrpc: "2.0", id: msg.id, result: { stopReason: "end_turn" } });
    return;
  }
  // 其他 method 一律回空物件
  if ("id" in msg) send({ jsonrpc: "2.0", id: msg.id, result: {} });
});
```

