```ts
/**
 * SessionRegistry — 可恢復 ACP session 的 per-chat 持久化記錄。
 *
 * 解決的問題：idle/crash/health_monitor 關掉 session 後，原 ACP context
 * 只能靠摘要注入降級恢復。此 registry 記住上一個 sessionId，讓下次
 * create() 能走 session/load 完整恢復。
 *
 * 設計決策：
 * - 單一 JSON 檔（chatId → record）而非 per-chat 檔：單人架構，量小。
 * - 走 atomicJson（排除手寫 tmp+rename：atomicJson 已含 Windows EPERM retry 與壞檔容錯）。
 * - 只在 ACP_SESSION_RESUME=true 時被呼叫（呼叫端閘控），本模組不讀 flag。
 * - 路徑函式優先讀 process.env.MEMORY_DIR（可測試性），fallback config.memoryDir。
 */
import path from "node:path";
import { readJsonFile, writeJsonFile } from "./atomicJson.js";
import { config } from "./config.js";

export interface ResumableSession {
  /** ACP session id（session/new 的回傳值）。 */
  sessionId: string;
  /** /agent pin 的 backend key；.env agent 時為 ""。 */
  backendKey: string;
  /** spawn 的 agent command（backend/.env 變更時做防呆比對）。 */
  agentCommand: string;
  /** session/new 當時的 cwd（session/load 需帶同值）。 */
  cwd: string;
  /** 最後寫入時間（epoch ms）。 */
  savedAt: number;
}

type RegistryFile = Record<string, ResumableSession>;

function registryPath(): string {
  const dir = process.env.MEMORY_DIR || config.memoryDir;
  return path.join(dir, "config", "acp-session-registry.json");
}

export async function loadResumable(chatId: number): Promise<ResumableSession | null> {
  const all = await readJsonFile<RegistryFile>(registryPath(), {});
  const rec = all[String(chatId)];
  if (!rec || !rec.sessionId) return null;
  return rec;
}

export async function saveResumable(chatId: number, rec: ResumableSession): Promise<void> {
  const all = await readJsonFile<RegistryFile>(registryPath(), {});
  all[String(chatId)] = rec;
  await writeJsonFile(registryPath(), all);
}

export async function clearResumable(chatId: number): Promise<void> {
  const all = await readJsonFile<RegistryFile>(registryPath(), {});
  if (!(String(chatId) in all)) return;
  delete all[String(chatId)];
  await writeJsonFile(registryPath(), all);
}
```

注意：`atomicJson.ts` 的實際匯出名若是 `readJson`/`writeJson` 等，改 import 並同步改本檔與 smoke test（先 grep 確認，不要瞎猜）。

