/**
 * Session lifecycle: transcript saving, fact extraction, working-state
 * persistence, restart handling, and pending-extract queue processing.
 *
 * Extracted from index.ts (P4 split).
 */
import { writeFile, mkdir, readFile, unlink } from "node:fs/promises";
import path from "node:path";
import type { Bot, Context, InputFile } from "grammy";
import type { ChatSession, SessionManager } from "./sessionManager.js";
import type { Scheduler } from "./scheduler.js";
import type { ScheduleStore } from "./schedule-store.js";
import { appendFactsDedup, listFacts } from "./memory.js";
import { config } from "./config.js";
import * as goalStore from "./goalStore.js";
import { fireGoalFirstTurn } from "./commands/goal.js";
import { shutdownAllSpecialists } from "./specialist.js";
import { stopPetApp } from "./pet-server.js";

// ─── Re-exports from working-state ────────────────────────────────────────────
import { writeWorkingState } from "./working-state.js";
export type { WorkingState } from "./working-state.js";
export { writeWorkingState } from "./working-state.js";

// ─── Types ────────────────────────────────────────────────────────────────────

export interface PendingExtract {
  userId: number;
  chatId: number;
  transcriptPath: string;
  reason: string;
  queuedAt: string;
}

// ─── Dependency injection ─────────────────────────────────────────────────────

export interface SessionExtractDeps {
  bot: Bot;
  sessions: SessionManager;
  MEMORY_DIR: string;
  RESTART_PENDING_FILE: string;
  PENDING_EXTRACT_FILE: string;
  getRestartPendingChatId: () => number | undefined;
  setRestartPendingChatId: (v: number | undefined) => void;
}

let _deps: SessionExtractDeps | null = null;

export function initSessionExtract(deps: SessionExtractDeps): void {
  _deps = deps;
}

function d(): SessionExtractDeps {
  if (!_deps) throw new Error("session-extract not initialized — call initSessionExtract first");
  return _deps;
}

// ─── withTimeout ──────────────────────────────────────────────────────────────

export function withTimeout<T>(
  p: Promise<T>,
  ms: number,
  label: string,
  onTimeout?: () => void,
): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    const t = setTimeout(() => {
      try { onTimeout?.(); } catch { /* noop */ }
      reject(new Error(`${label} timed out after ${ms}ms`));
    }, ms);
    p.then(
      (v) => { clearTimeout(t); resolve(v); },
      (e) => { clearTimeout(t); reject(e); },
    );
  });
}

// ─── parseFactsJson ───────────────────────────────────────────────────────────

export function parseFactsJson(raw: string): string[] {
  if (!raw) return [];
  const cleaned = raw.replace(/```(?:json)?/gi, "").replace(/```/g, "").trim();

  const start = cleaned.indexOf("[");
  const end = cleaned.lastIndexOf("]");
  if (start >= 0 && end > start) {
    for (let e = end; e > start; e = cleaned.lastIndexOf("]", e - 1)) {
      try {
        const arr = JSON.parse(cleaned.slice(start, e + 1));
        if (Array.isArray(arr)) {
          return arr.filter((x): x is string => typeof x === "string" && x.trim().length > 0);
        }
      } catch { /* keep trying shorter spans */ }
    }
  }

  const rawLines = cleaned.split(/\r?\n/).map((l) => l.trim()).filter(Boolean);
  const bulletRe = /^(?:[-*•]|\d+[.)])\s+/;
  const bulletCount = rawLines.filter((l) => bulletRe.test(l)).length;
  if (bulletCount < 2) return [];
  return rawLines
    .filter((l) => bulletRe.test(l))
    .map((l) => l.replace(bulletRe, "").trim())
    .filter((l) => l.length > 0);
}

// ─── saveTranscript ───────────────────────────────────────────────────────────

export async function saveTranscript(session: ChatSession): Promise<string> {
  const { MEMORY_DIR } = d();
  const now = new Date();
  const ts = now.toISOString().replace(/[:.]/g, "-").slice(0, 19);
  const filename = `session-${session.chatId}-${ts}.md`;

  let md = `# Session ${session.chatId}\n\nSaved: ${now.toISOString()}\n\n---\n\n`;
  for (const entry of session.history) {
    const time = new Date(entry.timestamp).toLocaleTimeString();
    const label = entry.role === "user" ? "👤 User" : "🤖 Assistant";
    md += `### ${label} (${time})\n\n${entry.text}\n\n---\n\n`;
  }

  const sessionsDir = path.join(MEMORY_DIR, "sessions");
  await mkdir(sessionsDir, { recursive: true });
  const filePath = path.join(sessionsDir, filename);
  await writeFile(filePath, md, "utf8");
  return filename;
}

// ─── extractFromSession ───────────────────────────────────────────────────────

export async function extractFromSession(session: ChatSession): Promise<number> {
  const { sessions } = d();
  const tag = `[memory] chat ${session.chatId}`;
  if (!session.userId) {
    console.log(`${tag}: extract skipped — no userId on session`);
    return 0;
  }
  if (session.history.length === 0) {
    console.log(`${tag}: extract skipped — session.history is empty`);
    return 0;
  }
  if (session.client.isClosed) {
    console.log(`${tag}: extract skipped — agent already closed`);
    return 0;
  }

  const transcript = session.history
    .map((h, i) => {
      let t = h.text;
      if (i === 0 && h.role === "user") {
        t = t.replace(
          /^\[Long-term memory about this user[\s\S]*?\[End memory\]\s*/,
          "",
        );
      }
      return `${h.role === "user" ? "U" : "A"}: ${t}`;
    })
    .join("\n")
    .slice(-12000);

  const existingFacts = await listFacts(session.userId);
  const existingBlock = existingFacts.length
    ? existingFacts.map((f) => `- ${f}`).join("\n")
    : "(目前沒有任何已記錄的事實)";

  const prompt =
    "你的任務：從對話紀錄中擷取值得「跨 session 長期記住的使用者事實」" +
    "（偏好、身份、環境、長期專案、重要決策、設定變更）。\n\n" +
    "規則：\n" +
    "1. 只記關於「使用者」的長期事實，排除一次性任務細節與關於助手本身的內容。\n" +
    "2. 下方 EXISTING_FACTS 已經被記住，**不要**重複輸出語意相同的項目。\n" +
    "3. 若對話中出現新的偏好、新決策、或與既有事實矛盾的更新，**務必**輸出。\n" +
    "4. 細小但明確的長期偏好也值得記（例如「偏好 X 風格」「選擇方案 Y」）。\n" +
    "5. 只輸出一個 JSON array，每個元素為一條簡短的繁體中文字串，" +
    "不要任何前後說明文字、不要 code fence。若沒有新事實，輸出 []。\n\n" +
    "EXISTING_FACTS:\n" + existingBlock + "\n\n" +
    "CONVERSATION:\n" + transcript;

  sessions.resetTurn(session);
  console.log(`${tag}: sending extract prompt (history=${session.history.length}, transcript=${transcript.length} chars, existing=${existingFacts.length})`);
  if (session.inflight) {
    console.warn(`${tag}: session already has an in-flight prompt; skipping extract`);
    return 0;
  }
  session.inflight = true;
  try {
    await session.client.prompt(prompt);
  } catch (err) {
    console.error(`${tag}: extract prompt failed:`, (err as Error).message);
    return 0;
  } finally {
    session.inflight = false;
    sessions.clearInactivityTimer(session);
  }
  console.log(`${tag}: extract raw buffer (${session.buffer.length} chars): ${session.buffer.slice(0, 400)}`);
  const facts = parseFactsJson(session.buffer);
  console.log(`${tag}: parsed ${facts.length} fact(s) from extract`);
  if (facts.length === 0) return 0;
  const added = await appendFactsDedup(session.userId, facts);
  console.log(`${tag}: appended ${added}/${facts.length} fact(s) after dedup`);
  return added;
}

// ─── transcriptFromMarkdown ───────────────────────────────────────────────────

export function transcriptFromMarkdown(md: string): string {
  const parts = md.split(/\n---\n/);
  const lines: string[] = [];
  let firstUserSeen = false;
  for (const part of parts) {
    const m = /^###\s+(👤 User|🤖 Assistant)[^\n]*\n\n([\s\S]*)$/.exec(part.trim());
    if (!m) continue;
    const role = m[1].includes("User") ? "U" : "A";
    let text = m[2].trim();
    if (role === "U" && !firstUserSeen) {
      firstUserSeen = true;
      text = text.replace(
        /^\[Long-term memory about this user[\s\S]*?\[End memory\]\s*/,
        "",
      );
    }
    lines.push(`${role}: ${text}`);
  }
  return lines.join("\n").slice(-12000);
}

// ─── enqueuePendingExtract ────────────────────────────────────────────────────

export async function enqueuePendingExtract(entry: PendingExtract): Promise<void> {
  const { MEMORY_DIR, PENDING_EXTRACT_FILE } = d();
  try {
    await mkdir(MEMORY_DIR, { recursive: true });
    const { appendFile } = await import("node:fs/promises");
    await appendFile(PENDING_EXTRACT_FILE, JSON.stringify(entry) + "\n", "utf8");
    console.log(`[memory] queued pending extract for chat ${entry.chatId} → ${entry.transcriptPath}`);
  } catch (err) {
    console.error("[memory] failed to queue pending extract:", (err as Error).message);
  }
}

// ─── extractFromTranscript ────────────────────────────────────────────────────

export async function extractFromTranscript(userId: number, transcript: string): Promise<number> {
  if (!transcript.trim()) return 0;
  const existingFacts = await listFacts(userId);
  const existingBlock = existingFacts.length
    ? existingFacts.map((f) => `- ${f}`).join("\n")
    : "(目前沒有任何已記錄的事實)";

  const prompt =
    "你的任務：從對話紀錄中擷取值得「跨 session 長期記住的使用者事實」" +
    "（偏好、身份、環境、長期專案、重要決策、設定變更）。\n\n" +
    "規則：\n" +
    "1. 只記關於「使用者」的長期事實，排除一次性任務細節與關於助手本身的內容。\n" +
    "2. 下方 EXISTING_FACTS 已經被記住，**不要**重複輸出語意相同的項目。\n" +
    "3. 若對話中出現新的偏好、新決策、或與既有事實矛盾的更新，**務必**輸出。\n" +
    "4. 細小但明確的長期偏好也值得記（例如「偏好 X 風格」「選擇方案 Y」）。\n" +
    "5. 只輸出一個 JSON array,每個元素為一條簡短的繁體中文字串," +
    "不要任何前後說明文字、不要 code fence。若沒有新事實,輸出 []。\n\n" +
    "EXISTING_FACTS:\n" + existingBlock + "\n\n" +
    "CONVERSATION:\n" + transcript;

  const { AcpClient } = await import("./acpClient.js");
  const extractEnv: Record<string, string> = {
    MEMORY_DIR: config.memoryDir,
    TG_ACTIVE_USER_ID: String(userId),
  };
  const client = new AcpClient({
    command: config.agent.command,
    args: config.agent.args,
    cwd: config.sessionCwd,
    env: extractEnv,
    promptRetries: config.acpPromptRetries,
    promptRetryBaseMs: config.acpPromptRetryBaseMs,
  });
  let buffer = "";
  client.on("update", (u) => {
    const up = u.update;
    if (up.sessionUpdate === "agent_message_chunk" || up.sessionUpdate === "agent_thought_chunk") {
      const content = up.content as { type?: string; text?: string } | undefined;
      if (content?.type === "text" && typeof content.text === "string") {
        buffer += content.text;
      }
    }
  });
  try {
    await client.initializeAndCreateSession(config.sessionCwd);
    await withTimeout(
      client.prompt(prompt),
      config.memoryExtractTimeoutMs,
      `pending-extract(user ${userId})`,
      () => client.cancel(),
    );
  } finally {
    await client.close().catch(() => {});
  }
  const facts = parseFactsJson(buffer);
  if (facts.length === 0) return 0;
  return appendFactsDedup(userId, facts);
}

// ─── processPendingExtractions ────────────────────────────────────────────────

export async function processPendingExtractions(): Promise<void> {
  const { PENDING_EXTRACT_FILE } = d();
  let raw: string;
  try {
    raw = await readFile(PENDING_EXTRACT_FILE, "utf8");
  } catch (err: any) {
    if (err?.code === "ENOENT") return;
    console.error("[memory] read pending-extract queue failed:", err.message);
    return;
  }
  const lines = raw.split(/\r?\n/).filter((l) => l.trim().length > 0);
  if (lines.length === 0) {
    await unlink(PENDING_EXTRACT_FILE).catch(() => {});
    return;
  }
  console.log(`[memory] processing ${lines.length} pending extract(s)`);
  const remaining: string[] = [];
  for (const line of lines) {
    let entry: PendingExtract;
    try {
      entry = JSON.parse(line);
    } catch {
      console.error(`[memory] pending entry is not valid JSON, dropping: ${line.slice(0, 120)}`);
      continue;
    }
    try {
      const md = await readFile(entry.transcriptPath, "utf8");
      const transcript = transcriptFromMarkdown(md);
      const added = await extractFromTranscript(entry.userId, transcript);
      console.log(`[memory] pending extract for chat ${entry.chatId}: added ${added} fact(s)`);
    } catch (err) {
      console.error(`[memory] pending extract for chat ${entry.chatId} failed: ${(err as Error).message}`);
      remaining.push(line);
    }
  }
  if (remaining.length === 0) {
    await unlink(PENDING_EXTRACT_FILE).catch(() => {});
  } else {
    await writeFile(PENDING_EXTRACT_FILE, remaining.join("\n") + "\n", "utf8");
    console.log(`[memory] ${remaining.length} pending extract(s) still queued`);
  }
}

// ─── handleRestart ────────────────────────────────────────────────────────────

export async function handleRestart(
  ctx: Context,
  opts: { reason?: string } = {},
): Promise<void> {
  const { bot, sessions, MEMORY_DIR, RESTART_PENDING_FILE,
    setRestartPendingChatId } = d();
  const isAllowed = (ctx: Context) => {
    const userId = ctx.from?.id;
    return userId !== undefined && config.allowedUserIds.includes(userId);
  };
  if (!isAllowed(ctx)) return;
  const reason = opts.reason?.trim() || "";
  const replyText = reason
    ? `🔄 Agent requested restart: ${reason}\nRestarting bridge… (extracting facts first)`
    : "Restarting bridge… (extracting facts first)";
  await ctx.reply(replyText);
  const chatId = ctx.chat!.id;
  const pendingSession = sessions.peek(chatId);
  const pendingCount = pendingSession?.history.length ?? 0;
  setRestartPendingChatId(chatId);
  try {
    await mkdir(MEMORY_DIR, { recursive: true });
    const marker: Record<string, unknown> = {
      chatId,
      userId: ctx.from?.id,
      requestedAt: Date.now(),
      pendingCount,
    };
    if (reason) marker.reason = reason;
    await writeFile(RESTART_PENDING_FILE, JSON.stringify(marker), "utf8");
  } catch (err) {
    console.error("[restart] failed to write pending marker:", err);
  }
  try {
    await writeWorkingState(chatId, reason);
  } catch (err) {
    console.error("[restart] failed to write working-state:", err);
  }
  const sessionCount = sessions.size();
  try {
    try { await bot.stop(); } catch { /* noop */ }
    try { await shutdownAllSpecialists(); } catch { /* noop */ }
    console.log(
      `[restart] stopping; ${sessionCount} session(s) to flush` +
        (reason ? ` (reason="${reason}")` : ""),
    );
    if (sessionCount === 0) {
      await bot.api.sendMessage(chatId, "ℹ️ No active session to extract facts from.");
    }
    await withTimeout(
      sessions.shutdown(),
      config.memoryExtractTimeoutMs + 30_000,
      "sessions.shutdown",
    );
  } catch (err) {
    console.error("[restart] graceful shutdown failed:", err);
    try {
      await bot.api.sendMessage(chatId, `⚠️ Graceful shutdown failed: ${(err as Error).message}`);
    } catch { /* can't send, already stopping */ }
  }
  try { stopPetApp(); } catch { /* noop */ }
  console.log("[restart] exiting for supervisor restart");
  process.exit(1);
}

// ─── maybeAutoResumeGoalAfterRestart ──────────────────────────────────────────

export async function maybeAutoResumeGoalAfterRestart(
  chatId: number,
  userId: number | undefined,
  restartReason?: string,
): Promise<void> {
  const { bot } = d();
  const fakeCtx = {
    chat: { id: chatId, type: "private" as const },
    from:
      userId !== undefined
        ? { id: userId, is_bot: false, first_name: "restart-resume" }
        : undefined,
    reply: async (text: string, extra?: any) =>
      bot.api.sendMessage(chatId, text, extra),
    replyWithPhoto: async (file: InputFile, extra?: any) =>
      bot.api.sendPhoto(chatId, file, extra),
    replyWithDocument: async (file: InputFile, extra?: any) =>
      bot.api.sendDocument(chatId, file, extra),
    api: bot.api,
  } as unknown as Context;

  await fireGoalFirstTurn(fakeCtx, chatId, userId, {
    source: "restart-resume",
    restartReason,
  });
}

// ─── onBeforeClose / onUnexpectedExit callbacks ───────────────────────────────

export async function onBeforeClose(s: ChatSession, closeReason?: string): Promise<void> {
  const { MEMORY_DIR, RESTART_PENDING_FILE, getRestartPendingChatId } = d();

  // Save working state before closing (same as /restart).
  try {
    await writeWorkingState(s.chatId, "session closed");
  } catch (err) {
    console.error(`[session ${s.chatId}] writeWorkingState on close failed:`, err);
  }

  // Archive session state (structured JSON for programmatic restoration).
  try {
    const { exportSession, saveArchive } = await import("./session-archive.js");
    const reason = (closeReason ?? "manual") as "idle" | "manual" | "reset" | "restart" | "crash" | "health_monitor";
    const archive = await exportSession(s, reason);
    await saveArchive(archive);
  } catch (err) {
    console.error(`[session ${s.chatId}] session archive failed:`, (err as Error).message);
  }

  let transcriptPath: string | undefined;
  if (s.history.length > 0) {
    try {
      const filename = await saveTranscript(s);
      transcriptPath = path.join(MEMORY_DIR, "sessions", filename);
      console.log(`[memory] chat ${s.chatId}: saved transcript → sessions/${filename}`);
      if (getRestartPendingChatId() === s.chatId) {
        try {
          const raw = await readFile(RESTART_PENDING_FILE, "utf8");
          const marker = JSON.parse(raw) as Record<string, unknown>;
          marker.savedFilename = filename;
          marker.savedCount = s.history.length;
          await writeFile(RESTART_PENDING_FILE, JSON.stringify(marker), "utf8");
        } catch (err) {
          console.error("[restart] failed to update pending marker with save info:", err);
        }
      }
    } catch (err) {
      console.error(`[memory] chat ${s.chatId}: saveTranscript on close failed:`, (err as Error).message);
    }
  }
  try {
    const added = await withTimeout(
      extractFromSession(s),
      config.memoryExtractTimeoutMs,
      `extract(chat ${s.chatId})`,
      () => {
        try { s.client.cancel(); } catch { /* noop */ }
      },
    );
    if (added > 0) {
      console.log(`[memory] chat ${s.chatId}: extracted ${added} new fact(s) on close`);
    }
  } catch (err) {
    const reason = (err as Error).message;
    console.error(`[memory] chat ${s.chatId}: extract on close failed:`, reason);
    if (s.userId && transcriptPath) {
      await enqueuePendingExtract({
        userId: s.userId,
        chatId: s.chatId,
        transcriptPath,
        reason,
        queuedAt: new Date().toISOString(),
      });
    }
  }
}

export async function onUnexpectedExit(s: ChatSession, code: number | null): Promise<void> {
  const { bot } = d();
  const notice = `⚠️ Agent 意外退出 (code=${code})，session 已重置。下次訊息會自動建立新 session。`;
  bot.api.sendMessage(s.chatId, notice).catch(() => {});

  // Archive session state even on crash (best-effort).
  try {
    const { exportSession, saveArchive } = await import("./session-archive.js");
    const reason = code === null ? "health_monitor" : "crash";
    const archive = await exportSession(s, reason);
    await saveArchive(archive);
  } catch (err) {
    console.error(`[session ${s.chatId}] session archive after unexpected exit failed:`, (err as Error).message);
  }

  if (s.history.length === 0) return;
  try {
    const filename = await saveTranscript(s);
    console.log(`[memory] chat ${s.chatId}: agent exited (code=${code}); saved transcript → sessions/${filename}`);
  } catch (err) {
    console.error(`[memory] chat ${s.chatId}: saveTranscript after unexpected exit failed:`, (err as Error).message);
  }
}

