// 一次性 probe：偵測 ACP adapter 是否宣告 loadSession capability。
// 原理：initializeOrLoadSession 帶假 resumeSessionId——
//   - stderr 出現 "session/load failed" → capability=true（有嘗試 load）
//   - resumed=true → capability=true 且 load 竟成功
//   - 都沒有 → capability=false（直接走 session/new）
// 用法: node probe-loadcap.mjs <label> <command> [args...]
import path from "node:path";
import { pathToFileURL } from "node:url";

const [label, command, ...args] = process.argv.slice(2);
const { AcpClient } = await import(
  pathToFileURL(path.resolve("G:/AI/telegram-kiro-bridge-main/dist/acpClient.js")).href
);

const client = new AcpClient({ command, args, cwd: "G:/AI/telegram-kiro-bridge-main", env: {} });
let stderrBuf = "";
client.on("stderr", (c) => { stderrBuf += c; });

const timer = setTimeout(() => {
  console.log(`${label}: TIMEOUT（60s 內未完成 handshake）`);
  process.exit(2);
}, 60_000);

try {
  const r = await client.initializeOrLoadSession(
    "G:/AI/telegram-kiro-bridge-main", [], "sess_probe_nonexistent_0000",
  );
  clearTimeout(timer);
  const attempted = stderrBuf.includes("session/load failed");
  if (r.resumed) console.log(`${label}: loadSession=true（且假 ID 竟 load 成功——需人工確認語意）`);
  else if (attempted) console.log(`${label}: loadSession=true（有嘗試 load，假 ID 失敗後 fallback new）`);
  else console.log(`${label}: loadSession=false（未宣告 capability，直接 session/new）`);
} catch (err) {
  clearTimeout(timer);
  console.log(`${label}: ERROR — ${err.message}`);
} finally {
  try { await client.close(); } catch {}
  process.exit(0);
}

